IF SM400 AND NOT M9050 AND X7D0 AND SM400 THEN  // INSP_SW Product Detect Delay
    TON(T5400, K10);  // 타이머 T5400 설정값=K10
ELSE
    T5400 := FALSE;
END_IF;
M51910 := SM400 AND X7D6 AND T5410;  // INSP_SW WorK    Clamp UpDetect
