M51922 := SM400 AND X7D3 AND T5422;  // INSP_SW WorK    EndS/W
IF SM400 AND X7D3 THEN  // INSP_SW WorK    EndS/W
    TON(T5422, K1);  // 타이머 T5422 설정값=K1
ELSE
    T5422 := FALSE;
END_IF;
M51923 := SM400 AND X7D4 AND T5423;  // INSP_SW WorK    PassS/W
IF SM400 AND X7D4 THEN  // INSP_SW WorK    PassS/W
    TON(T5423, K10);  // 타이머 T5423 설정값=K10
