// --- LOW_JIG#06 DEFINE ---


// --- [Title] MC Status ---
M1140 := NOT (NOT M300 OR M9209) AND NOT M60;  // Unit #08Auto    Mode
M1141 := NOT M300 OR M9209 AND NOT M60 AND NOT M1144;  // Unit #08Manu    Mode
IF R_TRIG(NOT M1144 AND M9200) THEN  // Unit #08Auto/   Manual  SLT
    M9209 := NOT M9209;  // FF (토글)
END_IF;
IF R_TRIG(M300) THEN  // Unit #08Auto/   Manual  SLT
    M9209 := FALSE;  // RST
END_IF;
M9090 := SM400 AND SM401;  // Unit #08Sub #01 Cycle   Stop
M9091 := SM400 AND SM401;  // Unit #08Sub #02 Cycle   Stop
M9092 := SM400 AND SM401;  // Unit #08Sub #03 Cycle   Stop
M9093 := SM400 AND SM401;  // Unit #08Sub #04 Cycle   Stop
