M9095 := SM400 AND SM401;  // Unit #08Sub #06 Cycle   Stop
M9096 := SM400 AND SM401;  // Unit #08Sub #07 Cycle   Stop
M9097 := SM400 AND SM401;  // Unit #08Sub #08 Cycle   Stop
