IF M1144 OR M1152 AND NOT M1153 THEN  // Unit #08Cycle   Stop    Timeout
    TON(T570, K600);  // 타이머 T570 설정값=K600
ELSE
    T570 := FALSE;
END_IF;
IF M50043 OR M9202 THEN  // Unit #08Force   Stop    Time
    TON(T571, D2);  // 타이머 T571 설정값=D2
ELSE
    T571 := FALSE;
