M1143 := NOT (NOT T570 AND NOT T571) AND M1142 AND T572;  // Unit #08Stop    Possible
IF NOT (NOT T570 AND NOT T571) AND M1142 THEN  // Unit #08Stop    Possible
    TON(T572, D3);  // 타이머 T572 설정값=D3
ELSE
    T572 := FALSE;
END_IF;
M1144 := L30301 AND NOT L10008 AND NOT SM401 AND NOT SM401 AND NOT SM401 OR M70 OR M1144 AND M1159 AND NOT M60 AND NOT M1143 AND T573;  // Unit #08Auto Run
IF L30301 AND NOT L10008 AND NOT SM401 AND NOT SM401 AND NOT SM401 OR M70 OR M1144 AND M1159 AND NOT M60 AND NOT M1143 THEN  // Unit #08Auto RunDelay
    TON(T573, D1);  // 타이머 T573 설정값=D1
ELSE
    T573 := FALSE;
END_IF;
IF R_TRIG((SM400) AND (M1144 OR M1152) AND M9204) THEN  // Unit #08Pause
    M1145 := NOT M1145;  // FF (토글)
END_IF;
IF NOT M1144 AND NOT M1152 THEN  // Unit #08Pause
    M1145 := FALSE;  // RST
END_IF;
M1146 := NOT L30100 AND NOT L30101 OR M70 OR M1146 AND M1141 AND M1159 AND NOT M1147 AND NOT M50043 AND NOT M9202 AND NOT T574;  // Unit #08All HomeOn
IF NOT L30100 AND NOT L30101 OR M70 OR M1146 AND M1141 AND M1159 AND NOT M1147 AND NOT M50043 AND NOT M9202 AND NOT T574 AND NOT M1153 THEN  // Unit #08Home On Timeout
    TON(T574, K100);  // 타이머 T574 설정값=K100
ELSE
    T574 := FALSE;
END_IF;
M9080 := SM400 AND SM401;  // Unit #08All HomeStopper
M9081 := SM400 AND SM401;  // Unit #08All HomeStopper
M9082 := SM400 AND SM401;  // Unit #08All HomeStopper
M9083 := SM400 AND SM401;  // Unit #08All HomeStopper
M9084 := SM400 AND SM401;  // Unit #08All HomeStopper
M9085 := SM400 AND SM401;  // Unit #08All HomeStopper
M9020 := SM400 AND SM400 AND M51911 AND NOT L20801 AND NOT L20806;  // Unit #08Sub #01 Home
M9021 := SM400 AND SM400 AND M51961 AND NOT L20821 AND NOT L20826;  // Unit #08Sub #02 Home
M9022 := SM400 AND SM400;  // Unit #08Sub #03 Home
M9023 := SM400 AND SM400;  // Unit #08Sub #04 Home
M9024 := SM400 AND SM400;  // Unit #08Sub #05 Home
M9025 := SM400 AND SM400;  // Unit #08Sub #06 Home
M9026 := SM400 AND SM400;  // Unit #08Sub #07 Home
M9027 := SM400 AND NOT M9080 AND NOT M9081 AND NOT M9082 AND NOT M9083 AND NOT M9084 AND NOT M9085;  // Unit #08Sub #08 Home
M1147 := M1146 OR M1147 AND NOT M50043 AND NOT M1158 AND NOT M9202 AND M9020 AND M9021 AND M9022 AND M9023 AND M9024 AND M9025 AND M9026 AND M9027 AND NOT T574;  // Unit #08All HomeOK
M1150 := SM401;  // Unit #08Unuse
IF R_TRIG(SM400 AND M9205) THEN  // Unit #08(1C)    Mode
    M1152 := NOT M1152;  // FF (토글)
END_IF;
IF NOT (M1141 AND NOT M1146 AND M1159 AND NOT M1143 AND M50046) OR NOT SM401 THEN  // Unit #08(1C)    Mode
    M1152 := FALSE;  // RST
END_IF;
M1153 := NOT (NOT SM401 AND NOT SM401 AND NOT SM401);  // Unit #08Busy
M1157 := NOT ((K2L11100 = K0) AND NOT L11108 AND NOT L11109);  // Unit #08M/C     Warning
M9010 := NOT (NOT L11120 AND NOT L11121 AND NOT L11122 AND NOT L11123 AND NOT L11124 AND NOT L11125 AND NOT L11126 AND NOT L11127 AND NOT L11128 AND NOT L11129);  // Unit #08Sub #01 Alarm
M9011 := NOT (NOT L11140 AND NOT L11141 AND NOT L11142 AND NOT L11143 AND NOT L11144 AND NOT L11145 AND NOT L11146 AND NOT L11147 AND NOT L11148 AND NOT L11149);  // Unit #08Sub #02 Alarm
M9012 := NOT (NOT L11160 AND NOT L11161 AND NOT L11162 AND NOT L11163 AND NOT L11164 AND NOT L11165 AND NOT L11166 AND NOT L11167 AND NOT L11168 AND NOT L11169);  // Unit #08Sub #03 Alarm
M9013 := NOT (NOT L11180 AND NOT L11181 AND NOT L11182 AND NOT L11183 AND NOT L11184 AND NOT L11185 AND NOT L11186 AND NOT L11187 AND NOT L11188 AND NOT L11189);  // Unit #08Sub #04 Alarm
M9014 := NOT (NOT L11190 AND NOT L11191 AND NOT L11192 AND NOT L11193 AND NOT L11194 AND NOT L11195 AND NOT L11196 AND NOT L11197 AND NOT L11198 AND NOT L11199);  // Unit #08Sub #05 Alarm
M9015 := SM401;  // Unit #08Sub #06 Alarm
M9016 := SM401;  // Unit #08Sub #07 Alarm
M9017 := SM401;  // Unit #08Sub #08 Alarm
M1158 := NOT (NOT M31 AND NOT M41 AND NOT M9010 AND NOT M9011 AND NOT M9012 AND NOT M9013 AND NOT M9014 AND NOT M9015 AND NOT M9016 AND NOT M9017);  // Unit #08M/C     Alarm
M1159 := M355;  // Unit #08Dorr AllClose OK
M9000 := M1141 AND NOT M1146 AND NOT M1152 AND NOT M60 AND M1159;  // Unit #08Manu    Mode    Able
M9001 := M1159 OR L29902;  // Unit #08Manu    Mode    Jog Able
M9002 := M1144 OR M1152 AND M1159 AND NOT M60;  // Unit #08Auto    Able
M9030 := SM400 AND NOT L20800 AND NOT M51900;  // Unit #08Sub #01 Product All Off
M9031 := SM400 AND NOT L20820 AND NOT M51950;  // Unit #08Sub #02 Product All Off
M9032 := SM400 AND NOT L20860;  // Unit #08Sub #03 Product All Off
M9033 := SM400 AND NOT L20880;  // Unit #08Sub #04 Product All Off
M9034 := SM400 AND SM400;  // Unit #08Sub #05 Product All Off
M9035 := SM400 AND SM400;  // Unit #08Sub #06 Product All Off
M9036 := SM400 AND SM400;  // Unit #08Sub #07 Product All Off
M9037 := SM400 AND SM400;  // Unit #08Sub #08 Product All Off
M9040 := M9030 AND M9031 AND M9032 AND M9033 AND M9034 AND M9035 AND M9036 AND M9037;  // Unit #08Product All Off
M9050 := NOT (NOT L29316);  // Unit #08Dry Run
IF M9099 THEN  // Unit #08INT-LOCKOff Time
    TON(T579, D4);  // 타이머 T579 설정값=D4
ELSE
    T579 := FALSE;
END_IF;
IF NOT (M1141 AND NOT T579) THEN  // Unit #08INT-LOCKOFF HSW
    M9099 := FALSE;  // RST
END_IF;

// --- [Title] Touch Lamp ---
M9300 := M1140;  // Unit #08Auto/   Manual  HLP
M9301 := M1144;  // Unit #08Auto    Start   HLP
M9302 := NOT M1144 AND NOT M1152;  // Unit #08Cycle   Stop HLP
M9303 := M1146 AND SM412 OR M1147;  // Unit #08Home    HLP
M9304 := M1145;  // Unit #08Pause   HLP
M9305 := M1152 AND M1142 AND SM412;  // Unit #08One     Cycle   HLP
M9306 := M1155;  // Unit #08Step    Mode HLP
M9307 := M9207;  // Unit #08Step++  HLP
M9308 := M1150;  // Unit #08Use     HLP

M9328 := (SM400) AND (M9428 AND NOT M51910 AND SM412 OR M51911);  // INSP_SW CLAMP   Up      LP
M9329 := M9429 AND NOT M51911 AND SM412 OR M51911;  // INSP_SW CLAMP   Down    LP

M9348 := (SM400) AND (M9448 AND NOT M51960 AND SM412 OR M51960);  // INSP_CO CLAMP   Up      LP
M9349 := M9449 AND NOT M51961 AND SM412 OR M51961;  // INSP_CO CLAMP   Down    LP

IF SM400 AND NOT M1140 AND NOT M1141 AND NOT M1144 THEN
    D20300 := K0;  // MOV  // #01 ZoneMode    Lamp
END_IF;
IF SM400 AND M1140 AND NOT M1144 THEN
    D20300 := K1;  // MOV  // #01 ZoneMode    Lamp
END_IF;
IF SM400 AND M1144 THEN
    D20300 := K2;  // MOV  // #01 ZoneMode    Lamp
END_IF;
IF SM400 AND M1141 THEN
    D20300 := K3;  // MOV  // #01 ZoneMode    Lamp
END_IF;
IF SM400 AND NOT M1147 THEN
    D20301 := K0;  // MOV  // #01 ZoneHome    Lamp
END_IF;
IF SM400 AND M1147 THEN
    D20301 := K1;  // MOV  // #01 ZoneHome    Lamp
END_IF;
IF SM400 AND NOT M1158 THEN
    D20302 := K0;  // MOV  // #01 ZoneError   Lamp
END_IF;
IF SM400 AND M1158 THEN
    D20302 := K1;  // MOV  // #01 ZoneError   Lamp
END_IF;
IF SM400 AND M1158 THEN
    D20302 := K2;  // MOV  // #01 ZoneError   Lamp
END_IF;
IF SM400 AND NOT M1157 THEN
    D20303 := K0;  // MOV  // #01 ZoneAlarm   Lamp
END_IF;
IF SM400 AND M1157 THEN
    D20303 := K1;  // MOV  // #01 ZoneAlarm   Lamp
END_IF;
IF SM400 AND M1157 THEN
    D20303 := K2;  // MOV  // #01 ZoneAlarm   Lamp
END_IF;

// --- [Title]Auto Step ---


// --- -. Sub01 : ST#04 RETURN C/V Work Auto Step ---


// --- ___Memory Set ---
IF SM400 AND M1144 AND M51900 THEN  // INSP_SW InMemory
    L20800 := TRUE;  // SET
END_IF;
IF SM400 AND L20800 AND NOT M51900 AND T5401 THEN  // INSP_SW InMemory
    L20800 := FALSE;  // RST
END_IF;
IF SM400 AND L20800 AND NOT M51900 THEN  // INSP_SW Product OFF     Delay
    TON(T5401, K30);  // 타이머 T5401 설정값=K30
ELSE
    T5401 := FALSE;
END_IF;
IF NOT (SM400 AND L20800) THEN  // INSP_SW CLAMP OK
    BKRST(L20801, K9);  // 블록리셋: L20801부터 K9개 OFF
END_IF;
IF SM400 AND L20800 AND SM400 AND M51924 AND T5439 THEN  // INSP_SW CLAMP OK
    BKRST(L20801, K9);  // 블록리셋: L20801부터 K9개 OFF
END_IF;
IF SM400 AND L20800 AND SM400 AND M51924 AND T5439 THEN
    D71400 := K0;  // MOV  // INSP_SW AutoStep
END_IF;
IF SM400 AND L20800 AND SM400 AND M51924 THEN
    TON(T5439, K20);  // 타이머 T5439 설정값=K20
ELSE
    T5439 := FALSE;
END_IF;
IF (SM400 AND L20800) AND (NOT (NOT M21851 AND NOT M21855) OR L29310) AND M9503 THEN  // INSP_SW READ OK
    L20803 := TRUE;  // SET
END_IF;
IF NOT ((SM400 AND L20800) AND (NOT (NOT M21851 AND NOT M21855) OR L29310) AND M9503 AND NOT M51922) AND M9504 AND M51910 AND T5430 THEN  // INSP_SW CLAMP OK
    L20801 := TRUE;  // SET
END_IF;
IF NOT ((SM400 AND L20800) AND (NOT (NOT M21851 AND NOT M21855) OR L29310) AND M9503 AND NOT M51922) AND M9504 AND M51910 THEN  // INSP_SW WorK    Start   Delay
    TON(T5430, K10);  // 타이머 T5430 설정값=K10
ELSE
    T5430 := FALSE;
END_IF;
IF NOT ((SM400 AND L20800) AND (NOT (NOT M21851 AND NOT M21855) OR L29310) AND M9503 AND NOT M51922) AND M9508 AND M21852 AND T5431 THEN  // INSP_SW WorkEnd OK
    L20806 := TRUE;  // SET
END_IF;
IF NOT ((SM400 AND L20800) AND (NOT (NOT M21851 AND NOT M21855) OR L29310) AND M9503 AND NOT M51922) AND M9508 AND M21852 THEN  // INSP_SW WorK    End     Delay
    TON(T5431, K10);  // 타이머 T5431 설정값=K10
ELSE
    T5431 := FALSE;
END_IF;
IF SM400 AND M1144 AND M51950 THEN  // INSP_CO InMemory
    L20820 := TRUE;  // SET
END_IF;
IF SM400 AND L20820 AND NOT M51950 AND T5451 THEN  // INSP_CO InMemory
    L20820 := FALSE;  // RST
END_IF;
IF SM400 AND L20820 AND NOT M51950 THEN  // INSP_CO Product OFF     Delay
    TON(T5451, K30);  // 타이머 T5451 설정값=K30
ELSE
    T5451 := FALSE;
END_IF;
IF NOT (SM400 AND L20820) THEN  // INSP_CO CLAMP OK
    BKRST(L20821, K9);  // 블록리셋: L20821부터 K9개 OFF
END_IF;
IF SM400 AND L20820 AND M9002 AND M51974 AND T5479 THEN  // INSP_CO CLAMP OK
    BKRST(L20821, K9);  // 블록리셋: L20821부터 K9개 OFF
END_IF;
IF SM400 AND L20820 AND M9002 AND M51974 AND T5479 THEN
    D71410 := K0;  // MOV  // INSP_CO AutoStep
END_IF;
IF SM400 AND L20820 AND M9002 AND M51974 THEN
    TON(T5479, K20);  // 타이머 T5479 설정값=K20
ELSE
    T5479 := FALSE;
END_IF;
IF (SM400 AND L20820) AND (NOT (NOT M21951 AND NOT M21955) OR L29310) AND M9553 THEN  // INSP_CO READ OK
    L20823 := TRUE;  // SET
END_IF;
IF NOT ((SM400 AND L20820) AND (NOT (NOT M21951 AND NOT M21955) OR L29310) AND M9553 AND NOT M51972) AND M9554 AND M51961 AND T5480 THEN  // INSP_CO CLAMP OK
    L20821 := TRUE;  // SET
END_IF;
IF NOT ((SM400 AND L20820) AND (NOT (NOT M21951 AND NOT M21955) OR L29310) AND M9553 AND NOT M51972) AND M9554 AND M51961 THEN  // INSP_CO WorK    Start   Delay
    TON(T5480, K10);  // 타이머 T5480 설정값=K10
ELSE
    T5480 := FALSE;
END_IF;
IF NOT ((SM400 AND L20820) AND (NOT (NOT M21951 AND NOT M21955) OR L29310) AND M9553 AND NOT M51972) AND M9558 AND M21952 AND T5481 THEN  // INSP_CO WorkEnd OK
    L20826 := TRUE;  // SET
END_IF;
IF NOT ((SM400 AND L20820) AND (NOT (NOT M21951 AND NOT M21955) OR L29310) AND M9553 AND NOT M51972) AND M9558 AND M21952 THEN  // INSP_CO WorK    End     Delay
    TON(T5481, K10);  // 타이머 T5481 설정값=K10
ELSE
    T5481 := FALSE;
END_IF;

// --- ___Work Select ---


// --- ___Auto Step ---
IF NOT (NOT M9505 AND NOT M9511) THEN
    D71400 := K0;  // MOV  // INSP_SW AutoStep
END_IF;
IF M1144 OR M1152 AND NOT M1142 AND M9500 THEN
    D71400 := K1;  // MOV  // INSP_SW AutoStep
END_IF;
IF M1144 OR M1152 AND NOT M1142 AND M9502 AND L20800 AND M51900 THEN
    D71400 := K3;  // MOV  // INSP_SW AutoStep
END_IF;
IF M1144 OR M1152 AND NOT M1142 AND M9502 AND L20800 AND NOT L20801 AND NOT M51910 AND NOT L20806 AND L20803 THEN
    D71400 := K4;  // MOV  // INSP_SW AutoStep
END_IF;
IF M1144 OR M1152 AND NOT M1142 AND M9502 AND L20800 AND L20803 AND NOT L20806 AND NOT M51911 AND SM401 THEN
    D71400 := K6;  // MOV  // INSP_SW AutoStep
END_IF;
IF M1144 OR M1152 AND NOT M1142 AND M9502 AND L20800 AND L20803 AND NOT L20806 AND L20801 THEN
    D71400 := K8;  // MOV  // INSP_SW AutoStep
END_IF;
IF M1144 OR M1152 AND NOT M1142 AND M9502 AND L20800 AND L20803 AND L20806 AND NOT M51911 THEN
    D71400 := K9;  // MOV  // INSP_SW AutoStep
END_IF;
IF NOT M1142 OR M9090 THEN
    DECO(D71400, K4);  // 디코드: D71400 → K4비트 전개
END_IF;
IF M1144 OR M1152 AND NOT M1145 THEN
    D71400 := D71400 + 1;  // INC
END_IF;
IF NOT M1142 OR M9090 THEN
    DECO(D71400, K5);  // 디코드: D71400 → K5비트 전개
END_IF;


// --- ___Auto Step ---
IF NOT (NOT M9555 AND NOT M9561) THEN
    D71410 := K0;  // MOV  // INSP_CO AutoStep
END_IF;
IF M1144 OR M1152 AND NOT M1142 AND M9550 THEN
    D71410 := K1;  // MOV  // INSP_CO AutoStep
END_IF;
IF M1144 OR M1152 AND NOT M1142 AND M9552 AND L20820 AND M51950 THEN
    D71410 := K3;  // MOV  // INSP_CO AutoStep
END_IF;
IF M1144 OR M1152 AND NOT M1142 AND M9552 AND L20820 AND NOT L20821 AND NOT M51960 AND NOT L20826 AND L20823 THEN
    D71410 := K4;  // MOV  // INSP_CO AutoStep
END_IF;
IF M1144 OR M1152 AND NOT M1142 AND M9552 AND L20820 AND L20823 AND NOT L20826 AND NOT M51961 AND SM401 THEN
    D71410 := K6;  // MOV  // INSP_CO AutoStep
